def extract_date_from_string(text):
    """
    Extract date from string and return in standardized format
    """
    if pd.isna(text) or text == "" or text is None:
        return None

    text = str(text)

    # Pattern 1: DD.MM.YY format (like 16.02.24)
    pattern1 = r'(\d{1,2})\.(\d{1,2})\.(\d{2,4})'
    match1 = re.search(pattern1, text)
    if match1:
        day, month, year = match1.groups()
        # Handle 2-digit years
        if len(year) == 2:
            year = "20" + year if int(year) <= 30 else "19" + year
        try:
            return datetime(int(year), int(month), int(day))
        except ValueError:
            pass

    # Pattern 2: DD/MM/YY or DD/MM/YYYY format
    pattern2 = r'(\d{1,2})/(\d{1,2})/(\d{2,4})'
    match2 = re.search(pattern2, text)
    if match2:
        day, month, year = match2.groups()
        # Handle 2-digit years
        if len(year) == 2:
            year = "20" + year if int(year) <= 30 else "19" + year
        try:
            return datetime(int(year), int(month), int(day))
        except ValueError:
            pass

    # Pattern 3: YYYY-MM-DD format
    pattern3 = r'(\d{4})-(\d{1,2})-(\d{1,2})'
    match3 = re.search(pattern3, text)
    if match3:
        year, month, day = match3.groups()
        try:
            return datetime(int(year), int(month), int(day))
        except ValueError:
            pass

    # Pattern 4: MM/DD/YY or MM/DD/YYYY format (US format)
    pattern4 = r'(\d{1,2})/(\d{1,2})/(\d{2,4})'
    match4 = re.search(pattern4, text)
    if match4:
        month, day, year = match4.groups()
        # Handle 2-digit years
        if len(year) == 2:
            year = "20" + year if int(year) <= 30 else "19" + year
        try:
            return datetime(int(year), int(month), int(day))
        except ValueError:
            pass

    # Pattern 5: DD-MM-YY or DD-MM-YYYY format
    pattern5 = r'(\d{1,2})-(\d{1,2})-(\d{2,4})'
    match5 = re.search(pattern5, text)
    if match5:
        day, month, year = match5.groups()
        # Handle 2-digit years
        if len(year) == 2:
            year = "20" + year if int(year) <= 30 else "19" + year
        try:
            return datetime(int(year), int(month), int(day))
        except ValueError:
            pass

    return None

# Process cells D6 to D100 and extract dates to column E
for row in range(6, 101):  # D6 to D100 (rows 6 to 100)
