import pandas as pd
import openpyxl
from openpyxl.utils.dataframe import dataframe_to_rows
import re

def transpose_worksheets_to_summary(input_path, output_path):
    # Load the workbook
    workbook = pd.ExcelFile(input_path)

    # Initialize list to store processed data
    summary_data = []

    # Process each worksheet except Summary
    for sheet_name in workbook.sheet_names:
        if sheet_name.lower() == 'summary':
            continue

        # Read the worksheet
        df = pd.read_excel(input_path, sheet_name=sheet_name, header=None)

        # Process the data from this sheet
        sheet_data = process_sheet_data(df, sheet_name)
        if sheet_data:
            summary_data.extend(sheet_data)

    # Create summary DataFrame
    summary_df = create_summary_dataframe(summary_data)

    # Save to output file
    save_to_excel(summary_df, output_path, input_path)

def process_sheet_data(df, sheet_name):
    """Process data from a single sheet and extract relevant information"""
    data_blocks = []
    current_block = []

    # Split data into blocks separated by blank lines
    for idx, row in df.iterrows():
        # Check if row is blank (all NaN or empty)
        if pd.isna(row).all() or (row.astype(str).str.strip() == '').all():
            if current_block:
                data_blocks.append(current_block)
                current_block = []
        else:
            # Get the first non-null value from the row
            row_data = None
            for col in df.columns:
                if pd.notna(row[col]) and str(row[col]).strip():
                    row_data = str(row[col]).strip()
                    break
            if row_data:
                current_block.append(row_data)

    # Add the last block if it exists
    if current_block:
        data_blocks.append(current_block)

    # Process each block
    processed_data = []
    for block in data_blocks:
        if len(block) >= 2:  # Need at least order and invoice info
            processed_block = extract_block_info(block, sheet_name)
            if processed_block:
                processed_data.append(processed_block)

    return processed_data

def extract_block_info(block, company_name):
    """Extract structured information from a data block"""
    result = {'Company': company_name}

    # Initialize fields
    order_no = ""
    invoice_no = ""
    issues = []
    details = []

    for item in block:
        item_clean = item.strip()

        # Extract Order No
        if item_clean.startswith("Order No:"):
            order_no = item_clean.replace("Order No:", "").strip()

        # Extract Invoice No
        elif item_clean.startswith("Invoice No:"):
            invoice_no = item_clean.replace("Invoice No:", "").strip()

        # Identify issues and details
        elif "no items delivered" in item_clean.lower():
            issues.append("No items delivered -")
        elif "invoice already exists" in item_clean.lower():
            issues.append("Invoice already exists for order")
        elif "line(" in item_clean.lower() and not item_clean.startswith(("Order No:", "Invoice No:")):
            # This is likely a product detail
            details.append(item_clean)
        elif len(item_clean) > 10 and not item_clean.startswith(("Order No:", "Invoice No:")):
            # Other potential details
            if "delivered" not in item_clean.lower() and "invoice" not in item_clean.lower():
                details.append(item_clean)

    # Build result
    result['Order No:'] = order_no
    result['Invoice No:'] = invoice_no

    # Add issues and details
    for i, issue in enumerate(issues, 1):
        result[f'Issue {i}'] = issue
        if i <= len(details):
            result[f'Detail {i}'] = details[i-1]

    # Add remaining details
    for i in range(len(issues), len(details)):
        result[f'Issue {i+1}'] = "No items delivered -"
        result[f'Detail {i+1}'] = details[i]

    return result

def create_summary_dataframe(data):
    """Create a DataFrame from the processed data"""
    if not data:
        return pd.DataFrame()

    # Get all possible columns
    all_columns = set()
    for row in data:
        all_columns.update(row.keys())

    # Define column order
    base_columns = ['Company', 'Order No:', 'Invoice No:']
    issue_detail_columns = []

    # Find max number of issue/detail pairs
    max_pairs = 0
    for row in data:
        for key in row.keys():
            if key.startswith('Issue '):
                pair_num = int(key.split()[1])
                max_pairs = max(max_pairs, pair_num)

    # Create issue/detail column pairs
    for i in range(1, max_pairs + 1):
        issue_detail_columns.extend([f'Issue {i}', f'Detail {i}'])

    ordered_columns = base_columns + issue_detail_columns

    # Create DataFrame
    df_data = []
    for row in data:
        df_row = {}
        for col in ordered_columns:
            df_row[col] = row.get(col, None)
        df_data.append(df_row)

    return pd.DataFrame(df_data)

def save_to_excel(summary_df, output_path, input_path):
    """Save the summary DataFrame to Excel file"""
    # Load original workbook to preserve other sheets
    try:
        wb = openpyxl.load_workbook(input_path)
    except:
        wb = openpyxl.Workbook()

    # Remove existing Summary sheet if it exists
    if 'Summary' in wb.sheetnames:
        wb.remove(wb['Summary'])

    # Create new Summary sheet
    ws = wb.create_sheet('Summary', 0)  # Insert as first sheet

    # Write data to worksheet
    for r in dataframe_to_rows(summary_df, index=False, header=True):
        ws.append(r)

    # Auto-adjust column widths
    for column in ws.columns:
        max_length = 0
        column_letter = column[0].column_letter
        for cell in column:
            try:
                if len(str(cell.value)) > max_length:
                    max_length = len(str(cell.value))
            except:
                pass
        adjusted_width = min(max_length + 2, 50)
        ws.column_dimensions[column_letter].width = adjusted_width

    # Save workbook
    wb.save(output_path)

# Execute the main function
input_path = "/Users/thomascahill/Documents/servalsheets 2/benchmark/spreadsheetbench/data/all_data_912_v0.1/spreadsheet/166-27/1_166-27_input.xlsx"
output_path = "/Users/thomascahill/Documents/servalsheets 2/benchmark/spreadsheetbench/data/all_data_912_v0.1/outputs/single_claude-sonnet-4-20250514/1_166-27_output.xlsx"

transpose_worksheets_to_summary(input_path, output_path)

