# Function to check if sequence follows the pattern
def check_sequence_pattern(sequence):
    # Remove any NaN or None values and convert to list
    seq = [x for x in sequence if pd.notna(x) and x is not None]

    if len(seq) == 0:
        return False

    # Check condition 2: first two numbers are zeros
    if len(seq) >= 2 and seq[0] == 0 and seq[1] == 0:
        return True

    # Find first non-zero element
    first_nonzero_idx = -1
    first_sign = None
    for i, val in enumerate(seq):
        if val != 0:
            first_nonzero_idx = i
            first_sign = 1 if val > 0 else -1
            break

    if first_nonzero_idx == -1:  # All zeros
        return False

    # Check pattern from first non-zero element
    sign_changed = False
    current_expected_sign = first_sign

    for i in range(first_nonzero_idx, len(seq)):
        val = seq[i]
        if val == 0:
            continue

        val_sign = 1 if val > 0 else -1

        if not sign_changed:
            if val_sign != first_sign:
                # First sign change occurred
                sign_changed = True
                current_expected_sign = val_sign
            # else still in initial sign phase
        else:
            # After sign change, should only see the new sign
            if val_sign != current_expected_sign:
                return False

    return sign_changed  # Pattern is valid only if sign actually changed

# Helper function to safely convert cell value to float
def safe_float_convert(cell_value):
    if cell_value is None:
        return None
    if isinstance(cell_value, str):
        if cell_value.strip() == '' or cell_value.strip() == 'NaN':
            return None
        try:
            return float(cell_value)
        except ValueError:
            return None
    try:
        return float(cell_value)
    except (ValueError, TypeError):
