    # Get cumulative sums from columns R-AF (columns 18-32)
    cumulative_sums = []
    for col in range(18, 33):  # R=18, S=19, ..., AF=32
        cell_value = ws.cell(row=row_num, column=col).value
        converted_value = safe_float_convert(cell_value)
